import{_ as n,o as r,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"15. Performance Management","description":"","frontmatter":{"title":"15. Performance Management","eba":"Biomedical Engineers 2025-2028","topics":["discipline"]},"headers":[],"relativePath":"ebas/biomedical-engineers/consultation-disputes/15-performance-management.md","filePath":"ebas/biomedical-engineers/consultation-disputes/15-performance-management.md"}'),t={name:"ebas/biomedical-engineers/consultation-disputes/15-performance-management.md"};function i(s,e,p,c,m,l){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_15-performance-management" tabindex="-1">15. Performance Management <a class="header-anchor" href="#_15-performance-management" aria-label="Permalink to &quot;15. Performance Management&quot;">​</a></h1><p><strong>15.1</strong> Application</p><p><strong>(a)</strong> An Employer is required to provide reasonable Performance Management to an Employee where performance issues are identified.</p><p><strong>(b)</strong> Performance Management includes reasonable actions to address performance by identifying performance deficits, the Employer&#39;s expected outcomes and performance measures, and strategies to meet those measures.</p><p><strong>(c)</strong> This clause applies to performance issues that:</p><p><strong>(i)</strong> Occur after the first 6 months of employment;</p><p><strong>(ii)</strong> Do not constitute Misconduct or Serious Misconduct (as defined at subclause 16.2);</p><p><strong>(iii)</strong> Occur prior to the Employee having been provided all reasonably practicable interventions to correct performance.</p><p><strong>(d)</strong> Nothing in this clause 15 will prevent the Employer from initiating the disciplinary procedure in accordance with <a href="/eba/ebas/biomedical-engineers/consultation-disputes/16-discipline.html">clause 16</a> – Discipline where a performance issue constitutes Misconduct or Serious Misconduct (as defined).</p><p><strong>15.2</strong> Performance Management Process An Employer may deal with performance issues either informally or formally.</p><p><strong>(a)</strong> Informal Informal Performance Management will generally involve direct discussions with the Employee, whilst a formal process will be more formal in character having regard to the performance management principles listed at 15.2(b)(i).</p><p><strong>(b)</strong> Formal Formal Performance Management will be more formal in character having regard to the performance management principles below, and may include the creation of a performance improvement plan.</p><p><strong>(i)</strong> Performance Management Principles The following principles will apply to a formal performance management process: <strong>(A)</strong> Clearly identify and explain the aspects of the Employee&#39;s performance that are unsatisfactory and the required level of performance; <strong>(B)</strong> Permitting an Employee to be represented in any formal meeting or process relating to formal performance development;</p><p><strong>(C)</strong> Consult with the Employee and Employee&#39;s representative (where applicable) on the content of any performance improvement plan (however titled) and provide a written copy of the plan; <strong>(D)</strong> Providing any additional reasonably practicable interventions (i.e. training, education and coaching) to support the employee to improve/develop their performance; <strong>(E)</strong> Providing the employee with a reasonable opportunity to address any concerns over a reasonable time period; <strong>(F)</strong> Scheduling regular feedback meetings to provide feedback on the employee&#39;s performance; and <strong>(G)</strong> Genuinely co-operating to undertake the process contained within this clause.</p><p>Plain language terms: performance review, PIP.</p>',15)])])}const f=n(t,[["render",i]]);export{d as __pageData,f as default};
